import { useEffect, useState } from "react";
import { MdOpenInNew } from "react-icons/md";

import "../styles/Anime.scss";
import {
  getTmdbImage,
  getTmdbMovieCollection,
  getTmdbMovieUrl,
} from "../config/tmdb";

const movieFilters = [
  { label: "Popular", value: "popular" },
  { label: "Top Rated", value: "top_rated" },
  { label: "Now Playing", value: "now_playing" },
  { label: "Upcoming", value: "upcoming" },
];

export default function MoviesPage() {
  const [movies, setMovies] = useState([]);
  const [filter, setFilter] = useState("popular");
  const [page, setPage] = useState(localStorage.getItem("currentMoviePage") || "1");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    localStorage.setItem("currentMoviePage", page);
  }, [page]);

  useEffect(() => {
    getMovies();
  }, [page, filter]);

  async function getMovies() {
    setLoading(true);
    const data = await getTmdbMovieCollection(`/movie/${filter}`, { page });
    setMovies(data);
    setLoading(false);
  }

  const handleMore = () => {
    setPage((prev) => String(Number(prev) + 1));
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const handleLess = () => {
    setPage((prev) => String(Math.max(Number(prev) - 1, 1)));
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  return (
    <section className="anime-page movie-page">
      <nav className="anime-nav-filter">
        <h2>TMDB Movies</h2>
        <select
          value={filter}
          onChange={(e) => {
            setPage("1");
            setFilter(e.target.value);
          }}
        >
          {movieFilters.map((option) => (
            <option key={option.value} value={option.value}>
              {option.label}
            </option>
          ))}
        </select>
      </nav>

      {loading && <p className="section-status">Loading TMDB movies...</p>}
      {!loading && (
        <div className="anime-grid movie-grid">
          {movies.map((movie) => (
            <a
              key={movie.id}
              className="card movie-card"
              href={getTmdbMovieUrl(movie.id)}
              target="_blank"
              rel="noreferrer"
            >
              <img className="card-image" src={getTmdbImage(movie.poster_path, "w500")} alt={movie.title} />
              <div className="info">
                <h3 className="card-title">{movie.title}</h3>
                <p className="movie-meta">
                  {(movie.release_date || "").slice(0, 4) || "N/A"} • {movie.vote_average?.toFixed(1) || "N/A"}
                </p>
              </div>
              <span className="tmdb-link">
                View on TMDB <MdOpenInNew />
              </span>
            </a>
          ))}
        </div>
      )}

      <div className="page-nav">
        {Number(page) > 1 && <button onClick={handleLess}>Go Back</button>}
        <button onClick={handleMore}>Next Page</button>
      </div>
    </section>
  );
}
